// AUTO-GENERATED from the official Seoul 25-district (자치구) boundary GeoJSON
// (southkorea/seoul-maps, KOSTAT 2013). Equirectangular projection scaled
// by cos(lat) so the real Seoul silhouette is undistorted. Do not hand-edit;
// regenerate via scripts/gen-seoul-map.py if the source changes.

export type SeoulDistrict = { name: string; nameKo: string; path: string; cx: number; cy: number };

export const SEOUL_MAP_W = 100.0;
export const SEOUL_MAP_H = 82.3;

// Geographic bounding box the silhouette was projected from (min/max over all
// district rings in the source GeoJSON). Lets us drop real lng/lat points onto
// the same SVG coordinate space as the district paths above. The cos(lat)
// scale factor cancels out in x, so the projection is a plain linear map.
export const SEOUL_BBOX = {
  minLng: 126.76700465024426,
  maxLng: 127.18543378919821,
  minLat: 37.42574929824175,
  maxLat: 37.698589417759045,
};

export function projectLngLat(lng: number, lat: number): { x: number; y: number } {
  return {
    x: ((lng - SEOUL_BBOX.minLng) / (SEOUL_BBOX.maxLng - SEOUL_BBOX.minLng)) * SEOUL_MAP_W,
    y: ((SEOUL_BBOX.maxLat - lat) / (SEOUL_BBOX.maxLat - SEOUL_BBOX.minLat)) * SEOUL_MAP_H,
  };
}

